// ActiveSidebarGroups returns a copy of groups with Active=true for the item
// whose Href best matches currentPath (longest-prefix match).
func ActiveSidebarGroups(groups []SidebarGroup, currentPath string) []SidebarGroup {
	out := make([]SidebarGroup, len(groups))
	bestLen := 0
	var bestGroup, bestItem int
	found := false
	for gi, g := range groups {
		out[gi] = SidebarGroup{Label: g.Label, Items: make([]SidebarItem, len(g.Items))}
		for ii, item := range g.Items {
			out[gi].Items[ii] = item
			if item.Href != "/" && strings.HasPrefix(currentPath, item.Href) && len(item.Href) > bestLen {
				bestLen = len(item.Href)
				bestGroup = gi
				bestItem = ii
				found = true
			}
		}
	}
	if found {
		out[bestGroup].Items[bestItem].Active = true
	}
	return out
}

